  const prompt = `Niche: ${niche}
Description: ${nicheDesc}

Produce 10 YouTube search keywords a creator in this niche would target. Mix broad + narrow + evergreen + trending angles. No duplicates. No quotes.

Return ONLY a JSON array of 10 strings: ["keyword 1", "keyword 2", ...]. No other text.`;

  try {
    const aiRes = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-opus-4-6',
        max_tokens: 400,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (aiRes.ok) {
      const body = await aiRes.json();
      const text = body.content?.[0]?.text || '[]';
