}

// For each unique keyword, run YouTube search + videos, compute score, upsert.
const keywords = Array.from(keywordMap.values());

for (const kw of keywords) {
  if (quotaExhausted) break;

  const searchUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(kw.keyword)}&type=video&maxResults=10&key=${ytKey}`;
  const searchRes = await fetchWithRetry(searchUrl, { method: 'GET' }, 'yt_search_kw');
  if (searchRes.quota) { quotaExhausted = true; break; }

  const totalResults = searchRes.ok ? (searchRes.json?.pageInfo?.totalResults || 0) : 0;
  const videoIds = searchRes.ok ? (searchRes.json?.items || []).map(i => i.id?.videoId).filter(Boolean) : [];

  let top10AvgViews = 0;
  if (videoIds.length > 0) {
    const vUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics&id=${videoIds.join(',')}&key=${ytKey}`;
    const vRes = await fetchWithRetry(vUrl, { method: 'GET' }, 'yt_videos_kw');
    if (vRes.quota) { quotaExhausted = true; break; }
    if (vRes.ok) {
      const items = vRes.json?.items || [];
      const views = items.map(v => parseInt(v.statistics?.viewCount || '0', 10)).filter(v => v > 0);
      top10AvgViews = views.length ? Math.round(views.reduce((a, b) => a + b, 0) / views.length) : 0;
    }
  }

  const acDemand = autocompleteDemandScore(kw.autocomplete_hits || 0);
  const svp = Math.round((kw.autocomplete_hits || 0) * 12.5);
  const compInv = competitionInverseScore(totalResults);
  const opportunity = Math.round(acDemand * 0.40 + Math.min(svp, 100) * 0.30 + compInv * 0.30);

  const row = {
    project_id: projectId,
    keyword: kw.keyword.slice(0, 300),
    normalized_keyword: kw.normalized_keyword.slice(0, 300),
    search_volume_proxy: svp,
    autocomplete_hits: kw.autocomplete_hits || 0,
    competing_videos_count: totalResults,
    competition_level: competitionLevel(totalResults),
    opportunity_score: Math.max(0, Math.min(100, opportunity)),
    seo_classification: seoClassification(totalResults, kw.autocomplete_hits || 0),
    related_keywords: (kw.related_suggestions || []).map(k => ({ keyword: String(k).slice(0, 300), autocomplete_hits: null })),
    trend_signal: null,
    source: kw.source || 'keyword_scan',
    last_scanned_at: new Date().toISOString()
  };

  try {
    const upsertRes = await fetch(`${supabaseUrl}/rest/v1/keywords?on_conflict=project_id,normalized_keyword`, {
      method: 'POST',
      headers: {
        ...sbHeaders,
        'Prefer': 'resolution=merge-duplicates,return=minimal'
      },
      body: JSON.stringify(row)
    });
    if (upsertRes.ok) {
      totalUpserted += 1;
    }
  } catch (_) { /* continue scanning */ }
}

if (data.batch_index + 1 < data.total_batches) {
  await sleep(2000);
}

return {
  json: {
    project_id: projectId,
    batch_index: data.batch_index,
    total_batches: data.total_batches,
    keywords_considered: keywords.length,
    keywords_upserted: totalUpserted,
    yt_queries_made: totalQueriesMade + keywords.length * 2,
    quota_exhausted: quotaExhausted
  }
};

// Aggregate + write a production_logs summary row.
const items = $input.all().map(i => i.json).filter(j => !j.skipped);

if (items.length === 0) {
  return [{ json: { success: true, keywords_scanned: 0, message: 'No seed keywords to scan' } }];
}

const projectId = items[0]?.project_id;
const totalUpserted = items.reduce((s, b) => s + (b.keywords_upserted || 0), 0);
const totalConsidered = items.reduce((s, b) => s + (b.keywords_considered || 0), 0);
const quota = items.some(b => b.quota_exhausted);

// Rough cost estimate: 2 YouTube units per keyword (search=100 + videos=1 per keyword, but we batch videos)
// Autocomplete is free. Very rough — real cost is tracked per API call elsewhere.
const ytCost = totalConsidered * 0.0005;
const claudeCost = 0.004; // Opus seed derivation, ~once per run

try {
  await fetch(`${$env.SUPABASE_URL}/rest/v1/production_logs`, {
    method: 'POST',
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: null,
      stage: 'keyword_scan',
      scene_number: null,
      action: 'scan_complete',
      status: quota ? 'partial_quota_exhausted' : 'success',
      duration_ms: null,
      cost_usd: Math.round((ytCost + claudeCost) * 10000) / 10000,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: true,
    project_id: projectId,
    keywords_scanned: totalUpserted,
    keywords_considered: totalConsidered,
    quota_exhausted: quota,
    batches_processed: items.length,
    finished_at: new Date().toISOString()
  }
}];
